import { NextResponse } from 'next/server'
import { db } from '@/lib/db'

// GET /api/home - Get homepage data
export async function GET() {
  try {
    // Get featured animes (top rated)
    const featured = await db.anime.findMany({
      where: { rating: { gte: 8 } },
      orderBy: [
        { rating: 'desc' },
        { views: 'desc' }
      ],
      take: 10,
      include: {
        seasons: {
          select: { id: true, number: true, episodes: true },
          orderBy: { number: 'asc' },
          take: 1
        }
      }
    })

    // Get recently added animes (by latest episodes)
    const latestAnimes = await db.anime.findMany({
      orderBy: { createdAt: 'desc' },
      take: 24,
      include: {
        seasons: {
          select: { id: true, number: true, episodes: true },
          orderBy: { number: 'asc' },
          take: 1
        }
      }
    })

    // Get most popular animes
    const popular = await db.anime.findMany({
      orderBy: { views: 'desc' },
      take: 24,
      include: {
        seasons: {
          select: { id: true, number: true, episodes: true },
          orderBy: { number: 'asc' },
          take: 1
        }
      }
    })

    // Get action animes
    const action = await db.anime.findMany({
      where: { genres: { contains: 'action' } },
      orderBy: { rating: 'desc' },
      take: 12
    })

    // Get movies
    const movies = await db.anime.findMany({
      where: { type: 'film' },
      orderBy: { rating: 'desc' },
      take: 12
    })

    // Get statistics
    const stats = await Promise.all([
      db.anime.count(),
      db.season.count(),
      db.episode.count(),
      db.videoSource.count()
    ])

    // Update featured animes
    if (featured.length > 0) {
      await db.anime.updateMany({
        where: { id: { in: featured.slice(0, 5).map(a => a.id) } },
        data: { isFeatured: true }
      })
    }

    return NextResponse.json({
      success: true,
      data: {
        featured: featured.slice(0, 5),
        latestAnimes,
        popular,
        action,
        movies,
        stats: {
          animes: stats[0],
          seasons: stats[1],
          episodes: stats[2],
          sources: stats[3]
        }
      }
    })

  } catch (error) {
    console.error('Error fetching home data:', error)
    return NextResponse.json(
      { success: false, error: 'Failed to fetch home data' },
      { status: 500 }
    )
  }
}

