import { NextRequest, NextResponse } from 'next/server'
import { db } from '@/lib/db'

// GET /api/animes - Get anime catalog with search and filters
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const search = searchParams.get('search') || ''
    const type = searchParams.get('type') || ''
    const sort = searchParams.get('sort') || 'title'
    const order = searchParams.get('order') || 'asc'
    const page = parseInt(searchParams.get('page') || '1')
    const limit = parseInt(searchParams.get('limit') || '24')
    const featured = searchParams.get('featured') === 'true'
    const trending = searchParams.get('trending') === 'true'
    const latest = searchParams.get('latest') === 'true'

    const skip = (page - 1) * limit

    // Build where clause
    const where: any = {}

    if (search) {
      where.title = {
        contains: search
      }
    }

    if (type) {
      where.type = type
    }

    if (featured) {
      where.isFeatured = true
    }

    if (trending) {
      where.isTrending = true
    }

    if (latest) {
      where.isLatest = true
    }

    // Build orderBy
    let orderBy: any = {}
    if (sort === 'title') {
      orderBy = { title: order }
    } else if (sort === 'year') {
      orderBy = { year: order }
    } else if (sort === 'rating') {
      orderBy = { rating: order }
    } else if (sort === 'episodes') {
      orderBy = { episodes: order }
    } else if (sort === 'views') {
      orderBy = { views: order }
    }

    // Get total count
    const total = await db.anime.count({ where })

    // Get animes with pagination
    const animes = await db.anime.findMany({
      where,
      orderBy,
      skip,
      take: limit,
      include: {
        seasons: {
          select: {
            id: true,
            number: true,
            title: true,
            episodes: true,
          },
          orderBy: { number: 'asc' }
        },
        _count: {
          select: { seasons: true }
        }
      }
    })

    return NextResponse.json({
      success: true,
      data: {
        animes: animes.map(anime => ({
          ...anime,
          seasonCount: anime._count.seasons,
          _count: undefined
        })),
        pagination: {
          page,
          limit,
          total,
          totalPages: Math.ceil(total / limit)
        }
      }
    })

  } catch (error) {
    console.error('Error fetching animes:', error)
    return NextResponse.json(
      { success: false, error: 'Failed to fetch animes' },
      { status: 500 }
    )
  }
}

