import { NextRequest, NextResponse } from 'next/server'
import { db } from '@/lib/db'

// GET /api/animes/[slug] - Get anime details with seasons and episodes
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ slug: string }> }
) {
  try {
    const { slug } = await params

    const anime = await db.anime.findUnique({
      where: { slug },
      include: {
        seasons: {
          orderBy: { number: 'asc' },
          include: {
            episodesRel: {
              orderBy: { number: 'asc' },
              include: {
                videoSources: {
                  orderBy: [
                    { language: 'asc' },
                    { priority: 'desc' }
                  ]
                }
              }
            }
          }
        }
      }
    })

    if (!anime) {
      return NextResponse.json(
        { success: false, error: 'Anime not found' },
        { status: 404 }
      )
    }

    // Increment view count
    await db.anime.update({
      where: { id: anime.id },
      data: { views: { increment: 1 } }
    })

    // Transform data for frontend
    const animeWithDetails = {
      ...anime,
      seasons: anime.seasons.map(season => ({
        id: season.id,
        number: season.number,
        title: season.title,
        episodeCount: season.episodes,
        episodes: season.episodesRel.map(episode => ({
          id: episode.id,
          number: episode.number,
          title: episode.title,
          thumbnail: episode.thumbnail,
          duration: episode.duration,
          isFiller: episode.isFiller,
          views: episode.views,
          sources: {
            vostfr: episode.videoSources
              .filter(s => s.language === 'vostfr')
              .map(s => ({
                id: s.id,
                source: s.source,
                url: s.url,
                quality: s.quality,
                priority: s.priority
              })),
            vf: episode.videoSources
              .filter(s => s.language === 'vf')
              .map(s => ({
                id: s.id,
                source: s.source,
                url: s.url,
                quality: s.quality,
                priority: s.priority
              }))
          }
        }))
      }))
    }

    return NextResponse.json({
      success: true,
      data: animeWithDetails
    })

  } catch (error) {
    console.error('Error fetching anime:', error)
    return NextResponse.json(
      { success: false, error: 'Failed to fetch anime' },
      { status: 500 }
    )
  }
}

