import { NextRequest, NextResponse } from 'next/server';
import { getAnimeMetadata } from '@/lib/metadata-service';
import { findAnimeSamaEpisode } from '@/lib/anime-sama';

// Lazy load database to avoid initialization issues
let _db: any = null;
async function getDb() {
  if (!_db) {
    try {
      const { db } = await import('@/lib/db');
      _db = db;
    } catch (error) {
      return null;
    }
  }
  return _db;
}

// Frivox data URL
const FRIVOX_DATA_URL = 'https://raw.githubusercontent.com/frivoxfr/ani-data/refs/heads/main/anime_data.json';

interface FrivoxMedia {
  name: string;
  lang: 'vf' | 'vostfr';
  media_type: string;
  season: number;
  episodes: string[];
}

interface FrivoxData {
  media: FrivoxMedia[];
}

// Cache for Frivox data
let cachedData: FrivoxData | null = null;
let lastFetchTime = 0;
const CACHE_DURATION = 60 * 60 * 1000; // 1 hour

async function fetchFrivoxData(): Promise<FrivoxData> {
  if (cachedData && Date.now() - lastFetchTime < CACHE_DURATION) {
    return cachedData;
  }

  const response = await fetch(FRIVOX_DATA_URL);
  if (!response.ok) {
    throw new Error(`Failed to fetch Frivox data: ${response.status}`);
  }

  const data: FrivoxData = await response.json();
  cachedData = data;
  lastFetchTime = Date.now();

  return data;
}

// Enrich anime data with metadata from TMDB/AniList
async function enrichAnimeData(name: string, baseData: {
  id: string;
  slug: string;
  title: string;
  episodeCount: number;
  type: string;
  languages: ('vf' | 'vostfr')[];
  seasons: { seasonNumber: number; episodes: number; lang: 'vf' | 'vostfr'; }[];
}) {
  try {
    const metadata = await getAnimeMetadata(name);

    return {
      ...baseData,
      coverImage: metadata.coverImage,
      bannerImage: metadata.bannerImage,
      description: metadata.description,
      year: metadata.year,
      rating: metadata.rating,
      genres: metadata.genres,
    };
  } catch (error) {
    console.error(`Failed to enrich ${name}:`, error);
    return {
      ...baseData,
      coverImage: null,
      bannerImage: null,
      description: null,
      year: null,
      rating: null,
      genres: [],
    };
  }
}

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);

  const search = searchParams.get('search');
  const name = searchParams.get('name');
  const season = searchParams.get('season');
  const episode = searchParams.get('episode');
  const lang = searchParams.get('lang') || 'vostfr';
  const page = parseInt(searchParams.get('page') || '1');
  const perPage = parseInt(searchParams.get('perPage') || '20');
  const fallback = searchParams.get('fallback') !== 'false'; // Anime-Sama fallback enabled by default

  try {
    const data = await fetchFrivoxData();

    // Get specific episode
    if (name && season && episode) {
      const seasonNum = parseInt(season);
      const epNum = parseInt(episode);

      const found = data.media.find(m => 
        m.name.toLowerCase() === name.toLowerCase() &&
        m.season === seasonNum &&
        m.lang === lang
      );

      // Episode found in Frivox
      if (found && epNum > 0 && epNum <= found.episodes.length) {
        return NextResponse.json({
          success: true,
          data: {
            url: found.episodes[epNum - 1],
            episode: epNum,
            totalEpisodes: found.episodes.length,
            source: 'frivox',
          },
        });
      }

      // === CHECK ADDITIONAL EPISODES FROM DATABASE ===
      try {
        const db = await getDb();
        if (db) {
          const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
          const additionalEp = await db.additionalEpisode.findFirst({
            where: {
              animeSlug: slug,
              season: seasonNum,
              episode: epNum,
              lang: lang as string,
              isActive: true,
            },
          });

          if (additionalEp) {
            return NextResponse.json({
              success: true,
              data: {
                url: additionalEp.url,
                episode: epNum,
                totalEpisodes: 0,
                source: additionalEp.source,
                player: additionalEp.player,
              },
            });
          }
        }
      } catch (dbError) {
        // Database models may not be available yet, skip to fallback
      }

      // === FALLBACK: Anime-Sama ===
      if (fallback) {
        console.log(`[Anime-Sama Fallback] Episode ${epNum} S${seasonNum} not in Frivox for "${name}"`);

        try {
          const animeSamaResult = await findAnimeSamaEpisode(name, seasonNum, epNum, lang as 'vf' | 'vostfr');

          if (animeSamaResult) {
            return NextResponse.json({
              success: true,
              data: {
                url: animeSamaResult.url,
                episode: epNum,
                totalEpisodes: 0, // Unknown from search
                source: 'anime-sama',
                player: animeSamaResult.player,
              },
            });
          }
        } catch (fallbackError) {
          console.error('[Anime-Sama Fallback] Error:', fallbackError);
        }
      }

      return NextResponse.json(
        { success: false, error: 'Episode not found' },
        { status: 404 }
      );
    }

    // Get anime details
    if (name) {
      const matching = data.media.filter(m => 
        m.name.toLowerCase() === name.toLowerCase()
      );

      if (matching.length === 0) {
        return NextResponse.json(
          { success: false, error: 'Anime not found' },
          { status: 404 }
        );
      }

      const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
      const languages = [...new Set(matching.map(m => m.lang))];
      const totalEpisodes = matching.reduce((sum, m) => sum + m.episodes.length, 0);
      const seasons = matching.map(m => ({
        seasonNumber: m.season,
        episodes: m.episodes.length,
        lang: m.lang,
      }));

      // Try to get additional episodes from database (may fail if models don't exist yet)
      let additionalEpisodes: any[] = [];
      let updateStatus: { hasUpdates: boolean } | null = null;

      try {
        const db = await getDb();
        if (db) {
          additionalEpisodes = await db.additionalEpisode.findMany({
            where: {
              animeSlug: slug,
              isActive: true,
            },
            orderBy: [
              { season: 'asc' },
              { episode: 'asc' },
            ],
          });

          updateStatus = await db.animeUpdate.findUnique({
            where: { animeSlug: slug },
          });
        }
      } catch (dbError) {
        // Database models may not be available yet, continue without additional episodes
      }

      // Merge additional episodes into seasons
      const additionalSeasons = new Map<string, { seasonNumber: number; episodes: number; lang: string; additionalEpisodes: number[] }>();

      for (const ep of additionalEpisodes) {
        const key = `${ep.season}-${ep.lang}`;
        if (!additionalSeasons.has(key)) {
          additionalSeasons.set(key, {
            seasonNumber: ep.season,
            episodes: 0,
            lang: ep.lang,
            additionalEpisodes: [],
          });
        }
        const seasonData = additionalSeasons.get(key)!;
        seasonData.additionalEpisodes.push(ep.episode);
        seasonData.episodes = Math.max(seasonData.episodes, ep.episode);
      }

      // Build final seasons list with additional episodes
      const finalSeasons = [...seasons];

      for (const [key, addSeason] of additionalSeasons) {
        const existingSeason = finalSeasons.find(
          s => s.seasonNumber === addSeason.seasonNumber && s.lang === addSeason.lang
        );

        if (existingSeason) {
          // Extend episode count if additional episodes go beyond
          const maxAddEp = Math.max(...addSeason.additionalEpisodes, 0);
          if (maxAddEp > existingSeason.episodes) {
            existingSeason.episodes = maxAddEp;
          }
        } else {
          // Add new season from additional episodes
          finalSeasons.push({
            seasonNumber: addSeason.seasonNumber,
            episodes: addSeason.episodes,
            lang: addSeason.lang as 'vf' | 'vostfr',
          });
        }
      }

      const baseData = {
        id: slug,
        slug,
        title: name.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
        episodeCount: totalEpisodes + additionalEpisodes.length,
        type: 'Anime',
        languages,
        seasons: finalSeasons,
        hasUpdates: updateStatus?.hasUpdates || additionalEpisodes.length > 0,
        additionalEpisodesCount: additionalEpisodes.length,
      };

      const enriched = await enrichAnimeData(name, baseData);

      return NextResponse.json({
        success: true,
        data: enriched,
      });
    }

    // Search
    if (search) {
      const query = search.toLowerCase();
      const matches = data.media.filter(m => 
        m.name.toLowerCase().includes(query)
      );

      // Get unique names
      const uniqueNames = [...new Set(matches.map(m => m.name))];

      // Paginate
      const start = (page - 1) * perPage;
      const paginatedNames = uniqueNames.slice(start, start + perPage);

      // Build response with images (limit concurrency)
      const results = await Promise.all(
        paginatedNames.map(async (name) => {
          const matching = data.media.filter(m => m.name === name);
          const languages = [...new Set(matching.map(m => m.lang))];
          const totalEpisodes = matching.reduce((sum, m) => sum + m.episodes.length, 0);

          const baseData = {
            id: name.toLowerCase().replace(/[^a-z0-9]+/g, '-'),
            slug: name.toLowerCase().replace(/[^a-z0-9]+/g, '-'),
            title: name.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
            episodeCount: totalEpisodes,
            type: 'Anime',
            languages,
            seasons: matching.map(m => ({
              seasonNumber: m.season,
              episodes: m.episodes.length,
              lang: m.lang,
            })),
          };

          return enrichAnimeData(name, baseData);
        })
      );

      return NextResponse.json({
        success: true,
        data: results,
        pagination: {
          page,
          perPage,
          total: uniqueNames.length,
          hasMore: start + perPage < uniqueNames.length,
        },
      });
    }

    // List all animes
    const uniqueNames = [...new Set(data.media.map(m => m.name))];
    const start = (page - 1) * perPage;
    const paginatedNames = uniqueNames.slice(start, start + perPage);

    // Build response with images (limit concurrency)
    const results = await Promise.all(
      paginatedNames.map(async (name) => {
        const matching = data.media.filter(m => m.name === name);
        const languages = [...new Set(matching.map(m => m.lang))];
        const totalEpisodes = matching.reduce((sum, m) => sum + m.episodes.length, 0);

        const baseData = {
          id: name.toLowerCase().replace(/[^a-z0-9]+/g, '-'),
          slug: name.toLowerCase().replace(/[^a-z0-9]+/g, '-'),
          title: name.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
          episodeCount: totalEpisodes,
          type: 'Anime',
          languages,
          seasons: matching.map(m => ({
            seasonNumber: m.season,
            episodes: m.episodes.length,
            lang: m.lang,
          })),
        };

        return enrichAnimeData(name, baseData);
      })
    );

    return NextResponse.json({
      success: true,
      data: results,
      pagination: {
        page,
        perPage,
        total: uniqueNames.length,
        hasMore: start + perPage < uniqueNames.length,
      },
    });
  } catch (error) {
    console.error('API Error:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch data' },
      { status: 500 }
    );
  }
}

