import { NextRequest, NextResponse } from 'next/server';
import { runSync, getSyncStatusData, getUpdatedAnimes } from '@/lib/sync-service';

/**
 * GET /api/sync - Get sync status and updated animes
 * POST /api/sync - Trigger a sync
 */
export async function GET(request: NextRequest) {
  try {
    const status = await getSyncStatusData();
    const updatedAnimes = await getUpdatedAnimes();

    return NextResponse.json({
      success: true,
      data: {
        status,
        updatedAnimes,
      },
    });
  } catch (error) {
    console.error('Sync status error:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to get sync status' },
      { status: 500 }
    );
  }
}

export async function POST(request: NextRequest) {
  try {
    const body = await request.json().catch(() => ({}));

    const { full, limit, skipExisting } = body;

    // Run sync in background for large operations
    const result = await runSync({
      full: full === true,
      limit: limit ? parseInt(limit, 10) : 20, // Default to 20 animes per sync
      skipExisting: skipExisting !== false, // Default to true
    });

    return NextResponse.json({
      success: result.success,
      data: {
        animesChecked: result.animesChecked,
        animesUpdated: result.animesUpdated,
        episodesAdded: result.episodesAdded,
        error: result.error,
      },
    });
  } catch (error) {
    console.error('Sync error:', error);
    return NextResponse.json(
      { success: false, error: 'Sync failed' },
      { status: 500 }
    );
  }
}

src/app/api/sync-anime-sama/route.ts.content:
import { NextRequest, NextResponse } from 'next/server';

// Anime-Sama.fun WordPress API
const API_BASE = 'https://anime-sama.fun/wp-json/wp/v2';

interface WordPressPost {
  id: number;
  slug: string;
  title: { rendered: string };
  content: { rendered: string };
  excerpt: { rendered: string };
  link: string;
  featured_media: number;
  _embedded?: {
    'wp:featuredmedia'?: Array<{
      source_url: string;
    }>;
  };
}

// Detect source from URL
function detectSource(url: string): string {
  const urlLower = url.toLowerCase();

  if (urlLower.includes('uqload')) return 'uqload';
  if (urlLower.includes('vudeo')) return 'vudeo';
  if (urlLower.includes('younetu')) return 'younetu';
  if (urlLower.includes('streamvid')) return 'streamvid';
  if (urlLower.includes('sblongvu')) return 'sblongvu';
  if (urlLower.includes('streamhide')) return 'streamhide';
  if (urlLower.includes('vido.lol')) return 'vidolol';
  if (urlLower.includes('vvide0')) return 'vvide0';
  if (urlLower.includes('upstream.to')) return 'upstream';
  if (urlLower.includes('vidmoly')) return 'vidmoly';
  if (urlLower.includes('sibnet')) return 'sibnet';
  if (urlLower.includes('sendvid')) return 'sendvid';
  if (urlLower.includes('myvi')) return 'myvi';
  if (urlLower.includes('doodstream')) return 'doodstream';
  if (urlLower.includes('streamtape')) return 'streamtape';
  if (urlLower.includes('mixdrop')) return 'mixdrop';
  if (urlLower.includes('voe')) return 'voe';

  return 'unknown';
}

// Detect language from URL or title
function detectLanguage(url: string, title: string): string {
  const titleLower = title.toLowerCase();
  const urlLower = url.toLowerCase();

  if (titleLower.includes('french') || titleLower.includes(' vf')) return 'vf';
  if (titleLower.includes('vostfr')) return 'vostfr';
  if (urlLower.includes('vf')) return 'vf';
  if (urlLower.includes('vostfr')) return 'vostfr';

  return 'vostfr';
}

// Sleep helper
function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// Fetch posts from WordPress API
async function fetchPosts(page: number, perPage: number = 50): Promise<{ posts: WordPressPost[]; total: number; totalPages: number }> {
  const response = await fetch(
    `${API_BASE}/posts?per_page=${perPage}&page=${page}&_embed=1`
  );

  const total = parseInt(response.headers.get('x-wp-total') || '0');
  const totalPages = parseInt(response.headers.get('x-wp-totalpages') || '0');
  const posts = await response.json() as WordPressPost[];

  return { posts, total, totalPages };
}

// Scrape episode data from anime page
async function scrapeEpisodes(post: WordPressPost) {
  try {
    const response = await fetch(post.link);
    const html = await response.text();

    // Extract episode data from hidden divs
    const episodeRegex = /<div[^>]*class="eps"[^>]*>([^<]+)<\/div>/gi;
    const episodes: { number: number; sources: string[] }[] = [];

    let match;
    while ((match = episodeRegex.exec(html)) !== null) {
      const data = match[1].trim();

      if (data.includes('!')) {
        const [numStr, urlsStr] = data.split('!');
        const number = parseInt(numStr);
        const sources = urlsStr.split(',').filter(url => url.trim());

        if (!isNaN(number) && sources.length > 0) {
          episodes.push({ number, sources });
        }
      }
    }

    const coverImage = post._embedded?.['wp:featuredmedia' as keyof typeof post._embedded]?.[0]?.source_url || null;

    return {
      slug: post.slug,
      title: post.title.rendered
        .replace(/&#8211;/g, '-')
        .replace(/&#8217;/g, "'")
        .replace(/&#038;/g, '&')
        .replace(/&amp;/g, '&'),
      description: post.excerpt.rendered
        .replace(/<[^>]*>/g, '')
        .replace(/&#8211;/g, '-')
        .replace(/&#8217;/g, "'")
        .trim(),
      coverImage,
      episodes,
      sourceUrl: post.link
    };
  } catch (error) {
    console.error(`Error scraping ${post.slug}:`, error);
    return null;
  }
}

// Save to database
async function saveToDatabase(anime: NonNullable<Awaited<ReturnType<typeof scrapeEpisodes>>>, db: any) {
  // Check if anime exists
  const existing = await db.anime.findUnique({
    where: { slug: anime.slug },
    include: {
      seasons: {
        include: {
          episodesRel: {
            include: { videoSources: true }
          }
        }
      }
    }
  });

  if (existing) {
    // Update existing - add new sources
    const season = existing.seasons[0];
    if (!season) return { status: 'no-season' };

    let newSources = 0;

    for (const ep of anime.episodes) {
      let episode = season.episodesRel.find((e: any) => e.number === ep.number);

      if (!episode) {
        episode = await db.episode.create({
          data: {
            seasonId: season.id,
            number: ep.number,
            title: `Episode ${ep.number}`
          }
        });
      }

      for (const url of ep.sources) {
        const existingSource = episode.videoSources.find((vs: any) => vs.url === url);
        if (!existingSource) {
          await db.videoSource.create({
            data: {
              episodeId: episode.id,
              source: detectSource(url),
              url: url,
              language: detectLanguage(url, anime.title)
            }
          });
          newSources++;
        }
      }
    }

    return { status: 'updated', newSources };
  }

  // Create new anime
  await db.anime.create({
    data: {
      slug: anime.slug,
      title: anime.title,
      description: anime.description || null,
      coverImage: anime.coverImage,
      type: anime.title.toLowerCase().includes('film') ? 'film' : 'anime',
      episodes: anime.episodes.length,
      seasons: {
        create: {
          number: 1,
          title: 'Season 1',
          episodes: anime.episodes.length,
          episodesRel: {
            create: anime.episodes.map(ep => ({
              number: ep.number,
              title: `Episode ${ep.number}`,
              videoSources: {
                create: ep.sources.map(url => ({
                  source: detectSource(url),
                  url: url,
                  language: detectLanguage(url, anime.title)
                }))
              }
            }))
          }
        }
      }
    }
  });

  return { status: 'created', episodes: anime.episodes.length };
}

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const page = parseInt(searchParams.get('page') || '1');
  const perPage = parseInt(searchParams.get('perPage') || '20');

  try {
    // Import database
    const { db } = await import('@/lib/db');

    // Get sync status
    const syncStatus = await db.syncStatus.findFirst({
      orderBy: { createdAt: 'desc' }
    });

    // If requesting status only
    if (searchParams.get('status') === 'true') {
      return NextResponse.json({
        success: true,
        data: {
          lastSync: syncStatus?.lastSyncAt,
          status: syncStatus?.status || 'idle',
          animesUpdated: syncStatus?.animesUpdated || 0,
          episodesAdded: syncStatus?.episodesAdded || 0
        }
      });
    }

    // Check if sync is already running
    if (syncStatus?.status === 'syncing') {
      return NextResponse.json({
        success: false,
        error: 'Sync already in progress'
      });
    }

    // Create sync status
    const newSyncStatus = await db.syncStatus.create({
      data: { status: 'syncing' }
    });

    // Fetch posts
    const { posts, total, totalPages } = await fetchPosts(page, perPage);

    let created = 0;
    let updated = 0;
    let newSources = 0;

    // Process each post
    for (const post of posts) {
      const scraped = await scrapeEpisodes(post);

      if (scraped && scraped.episodes.length > 0) {
        const result = await saveToDatabase(scraped, db);

        if (result.status === 'created') {
          created++;
        } else if (result.status === 'updated') {
          updated++;
          newSources += result.newSources;
        }
      }

      await sleep(100);
    }

    // Update sync status
    await db.syncStatus.update({
      where: { id: newSyncStatus.id },
      data: {
        status: 'idle',
        lastSyncAt: new Date(),
        animesUpdated: created + updated,
        episodesAdded: newSources
      }
    });

    return NextResponse.json({
      success: true,
      data: {
        page,
        totalPages,
        total,
        processed: posts.length,
        created,
        updated,
        newSources,
        hasMore: page < totalPages,
        nextUrl: page < totalPages 
          ? `/api/sync-anime-sama?page=${page + 1}&perPage=${perPage}`
          : null
      }
    });
  } catch (error) {
    console.error('Sync error:', error);

    return NextResponse.json({
      success: false,
      error: String(error)
    }, { status: 500 });
  }
}

// POST for full sync
export async function POST(request: NextRequest) {
  const body = await request.json().catch(() => ({}));
  const maxPages = body.maxPages || 5; // Sync 5 pages by default

  try {
    const { db } = await import('@/lib/db');

    // Create sync status
    const syncStatus = await db.syncStatus.create({
      data: { status: 'syncing' }
    });

    let totalCreated = 0;
    let totalUpdated = 0;
    let totalNewSources = 0;

    for (let page = 1; page <= maxPages; page++) {
      const { posts, totalPages } = await fetchPosts(page, 50);

      for (const post of posts) {
        const scraped = await scrapeEpisodes(post);

        if (scraped && scraped.episodes.length > 0) {
          const result = await saveToDatabase(scraped, db);

          if (result.status === 'created') {
            totalCreated++;
          } else if (result.status === 'updated') {
            totalUpdated++;
            totalNewSources += result.newSources;
          }
        }

        await sleep(100);
      }

      // Stop if we've reached the end
      if (page >= totalPages) break;
    }

    // Update sync status
    await db.syncStatus.update({
      where: { id: syncStatus.id },
      data: {
        status: 'idle',
        lastSyncAt: new Date(),
        lastFullSyncAt: new Date(),
        animesUpdated: totalCreated + totalUpdated,
        episodesAdded: totalNewSources
      }
    });

    return NextResponse.json({
      success: true,
      data: {
        pagesProcessed: maxPages,
        created: totalCreated,
        updated: totalUpdated,
        newSources: totalNewSources
      }
    });
  } catch (error) {
    console.error('Full sync error:', error);

    return NextResponse.json({
      success: false,
      error: String(error)
    }, { status: 500 });
  }
}

