import { NextRequest, NextResponse } from 'next/server';
import {
  searchAnime,
  getTrendingAnime,
  getPopularAnime,
  getRecentAnime,
  getSeasonalAnime,
  getAnimeByGenre,
  advancedSearch,
  getGenres,
  getAnimeById,
} from '@/lib/anilist';

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);

  const action = searchParams.get('action');
  const search = searchParams.get('search');
  const id = searchParams.get('id');
  const genre = searchParams.get('genre');
  const year = searchParams.get('year');
  const season = searchParams.get('season');
  const format = searchParams.get('format');
  const status = searchParams.get('status');
  const sort = searchParams.get('sort') || 'POPULARITY_DESC';
  const page = parseInt(searchParams.get('page') || '1');
  const perPage = parseInt(searchParams.get('perPage') || '20');

  try {
    let result;

    // Search
    if (search) {
      result = await searchAnime(search, page, perPage, sort);
      return NextResponse.json({
        success: true,
        data: result.animes,
        pagination: {
          page,
          perPage,
          total: result.pageInfo.total,
          lastPage: result.pageInfo.lastPage,
          hasMore: result.pageInfo.hasNextPage,
        },
      });
    }

    // Get by ID
    if (id) {
      const anime = await getAnimeById(parseInt(id));
      return NextResponse.json({
        success: true,
        data: anime,
      });
    }

    // Get genres
    if (action === 'genres') {
      const genres = await getGenres();
      return NextResponse.json({
        success: true,
        data: genres,
      });
    }

    // Trending
    if (action === 'trending') {
      result = await getTrendingAnime(page, perPage);
      return NextResponse.json({
        success: true,
        data: result.animes,
        pagination: {
          page,
          perPage,
          total: result.pageInfo.total,
          hasMore: result.pageInfo.hasNextPage,
        },
      });
    }

    // Popular
    if (action === 'popular') {
      result = await getPopularAnime(page, perPage);
      return NextResponse.json({
        success: true,
        data: result.animes,
        pagination: {
          page,
          perPage,
          total: result.pageInfo.total,
          hasMore: result.pageInfo.hasNextPage,
        },
      });
    }

    // Recent
    if (action === 'recent') {
      result = await getRecentAnime(page, perPage);
      return NextResponse.json({
        success: true,
        data: result.animes,
        pagination: {
          page,
          perPage,
          total: result.pageInfo.total,
          hasMore: result.pageInfo.hasNextPage,
        },
      });
    }

    // Seasonal
    if (action === 'seasonal') {
      const yearNum = year ? parseInt(year) : undefined;
      const seasonVal = season as 'WINTER' | 'SPRING' | 'SUMMER' | 'FALL' | undefined;
      result = await getSeasonalAnime(yearNum, seasonVal, page, perPage);
      return NextResponse.json({
        success: true,
        data: result.animes,
        pagination: {
          page,
          perPage,
          total: result.pageInfo.total,
          hasMore: result.pageInfo.hasNextPage,
        },
      });
    }

    // By genre
    if (genre) {
      result = await getAnimeByGenre(genre, page, perPage);
      return NextResponse.json({
        success: true,
        data: result.animes,
        pagination: {
          page,
          perPage,
          total: result.pageInfo.total,
          hasMore: result.pageInfo.hasNextPage,
        },
      });
    }

    // Advanced search with filters
    if (year || format || status || season) {
      result = await advancedSearch({
        year: year ? parseInt(year) : undefined,
        season: season as 'WINTER' | 'SPRING' | 'SUMMER' | 'FALL' | undefined,
        format: format || undefined,
        status: status || undefined,
        sort,
        page,
        perPage,
      });
      return NextResponse.json({
        success: true,
        data: result.animes,
        pagination: {
          page,
          perPage,
          total: result.pageInfo.total,
          lastPage: result.pageInfo.lastPage,
          hasMore: result.pageInfo.hasNextPage,
        },
      });
    }

    // Default: get popular
    result = await getPopularAnime(page, perPage);
    return NextResponse.json({
      success: true,
      data: result.animes,
      pagination: {
        page,
        perPage,
        total: result.pageInfo.total,
        hasMore: result.pageInfo.hasNextPage,
      },
    });
  } catch (error) {
    console.error('API Error:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch anime' },
      { status: 500 }
    );
  }
}

