import { NextRequest, NextResponse } from 'next/server';

// Stream proxy for AnimeAPI M3U8 URLs with required headers
export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  let url = searchParams.get('url');
  const m3u8 = searchParams.get('m3u8');
  const headersParam = searchParams.get('headers');

  // Support both 'url' and 'm3u8' parameter
  if (!url && m3u8) {
    url = m3u8;
  }

  if (!url) {
    return NextResponse.json(
      { error: 'URL parameter required' },
      { status: 400 }
    );
  }

  try {
    // Parse headers if provided
    let headers: Record<string, string> = {};
    if (headersParam) {
      try {
        headers = JSON.parse(decodeURIComponent(headersParam));
      } catch {
        // Ignore parse errors
      }
    }

    // Add essential headers if not present
    if (!headers['User-Agent']) {
      headers['User-Agent'] = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36';
    }

    // Fetch the content
    const response = await fetch(url, {
      headers: {
        ...headers,
        'Accept': '*/*',
        'Accept-Language': 'en-US,en;q=0.9',
      },
    });

    if (!response.ok) {
      return NextResponse.json(
        { error: `Failed to fetch stream: ${response.status}` },
        { status: response.status }
      );
    }

    const contentType = response.headers.get('content-type') || 'application/octet-stream';

    // For M3U8 files, we need to rewrite relative URLs to use our proxy
    if (contentType.includes('mpegurl') || url.includes('.m3u8')) {
      const text = await response.text();

      // Get base URL for resolving relative paths
      const baseUrl = url.substring(0, url.lastIndexOf('/') + 1);

      // Rewrite relative URLs to proxy through our API
      const rewritten = text
        .split('\n')
        .map(line => {
          // Skip comments and empty lines
          if (line.startsWith('#') || line.trim() === '') {
            // But rewrite URI in EXT-X-KEY to proxy through us
            if (line.includes('URI="')) {
              return line.replace(/URI="([^"]+)"/, (match, uri) => {
                if (uri.startsWith('http')) {
                  return `URI="/api/stream?url=${encodeURIComponent(uri)}"`;
                }
                return `URI="/api/stream?url=${encodeURIComponent(baseUrl + uri)}"`;
              });
            }
            return line;
          }

          // Make relative URLs absolute and proxy through us
          if (line.startsWith('http')) {
            // Already absolute - proxy through us
            return `/api/stream?url=${encodeURIComponent(line)}`;
          }
          // Relative - make absolute and proxy
          return `/api/stream?url=${encodeURIComponent(baseUrl + line)}`;
        })
        .join('\n');

      return new NextResponse(rewritten, {
        status: 200,
        headers: {
          'Content-Type': 'application/vnd.apple.mpegurl',
          'Access-Control-Allow-Origin': '*',
          'Cache-Control': 'no-cache',
        },
      });
    }

    // For other content (TS segments, etc.), just proxy
    const arrayBuffer = await response.arrayBuffer();

    return new NextResponse(arrayBuffer, {
      status: 200,
      headers: {
        'Content-Type': contentType,
        'Access-Control-Allow-Origin': '*',
        'Cache-Control': 'public, max-age=3600',
      },
    });

  } catch (error) {
    console.error('Stream proxy error:', error);
    return NextResponse.json(
      { error: 'Failed to proxy stream' },
      { status: 500 }
    );
  }
}

