import { NextRequest, NextResponse } from 'next/server';
import { getAnimeList, searchAnime, getGenres, getAvailableYears } from '@/lib/anilist';

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);

    const page = parseInt(searchParams.get('page') || '1');
    const limit = parseInt(searchParams.get('limit') || '50');
    const search = searchParams.get('search') || undefined;
    const genre = searchParams.get('genre') || undefined;
    const year = searchParams.get('year') ? parseInt(searchParams.get('year')!) : undefined;
    const format = searchParams.get('format') || undefined;
    const status = searchParams.get('status') || undefined;

    // Sort mapping
    const sortMap: Record<string, string> = {
      'title_asc': 'TITLE_ROMAJI',
      'title_desc': 'TITLE_ROMAJI_DESC',
      'year_desc': 'START_DATE_DESC',
      'year_asc': 'START_DATE',
      'popularity': 'POPULARITY_DESC',
      'score': 'SCORE_DESC',
    };
    const sort = searchParams.get('sort') || 'popularity';
    const anilistSort = sortMap[sort] || 'POPULARITY_DESC';

    // If it's a filter request (for dropdowns)
    if (searchParams.get('filters') === 'true') {
      const genres = await getGenres();
      const years = getAvailableYears();

      return NextResponse.json({
        success: true,
        data: {
          genres,
          years,
          formats: ['TV', 'MOVIE', 'OVA', 'ONA', 'SPECIAL', 'MUSIC'],
          statuses: ['RELEASING', 'FINISHED', 'NOT_YET_RELEASED', 'CANCELLED', 'HIATUS'],
        },
      });
    }

    // Search or list
    let result;
    if (search) {
      result = await searchAnime(search, page, limit);
    } else {
      result = await getAnimeList({
        page,
        perPage: limit,
        sort: anilistSort,
        genre,
        year,
        format,
        status,
      });
    }

    return NextResponse.json({
      success: true,
      data: result.animes,
      pagination: {
        page,
        limit,
        total: result.pageInfo.total,
        totalPages: 'lastPage' in result.pageInfo ? result.pageInfo.lastPage : Math.ceil(result.pageInfo.total / limit),
        hasMore: result.pageInfo.hasNextPage,
      },
    });
  } catch (error) {
    console.error('Error in anime API:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch anime' },
      { status: 500 }
    );
  }
}

