import { NextRequest, NextResponse } from 'next/server';
import { getAnimeById } from '@/lib/anilist';
import { getVideoSources } from '@/lib/videosources';

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    // Parse the ID - could be "anilist-123" or just "123"
    let anilistId: number;
    if (id.startsWith('anilist-')) {
      anilistId = parseInt(id.replace('anilist-', ''));
    } else {
      anilistId = parseInt(id);
    }

    if (isNaN(anilistId)) {
      return NextResponse.json(
        { success: false, error: 'Invalid anime ID' },
        { status: 400 }
      );
    }

    // Fetch anime details from AniList
    const anime = await getAnimeById(anilistId);

    if (!anime) {
      return NextResponse.json(
        { success: false, error: 'Anime not found' },
        { status: 404 }
      );
    }

    // Get available video sources
    const videoSources = await getVideoSources(anime.id);

    return NextResponse.json({
      success: true,
      data: {
        ...anime,
        videoSources,
      },
    });
  } catch (error) {
    console.error('Error fetching anime details:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch anime details' },
      { status: 500 }
    );
  }
}

