  try {
    const { searchParams } = new URL(request.url);
    const animeId = searchParams.get('animeId');
    const episode = searchParams.get('episode') ? parseInt(searchParams.get('episode')!) : undefined;
    const language = searchParams.get('language') as 'VF' | 'VOSTFR' | null;

    if (!animeId) {
      return NextResponse.json(
        { success: false, error: 'animeId is required' },
        { status: 400 }
      );
    }

    let sources;
    if (episode !== undefined) {
      sources = await getVideoSources(animeId, episode, language || undefined);
    } else {
      sources = await getAllVideoSourcesForAnime(animeId);
    }

    return NextResponse.json({
      success: true,
      data: sources,
    });
  } catch (error) {
    console.error('Error fetching video sources:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch video sources' },
      { status: 500 }
    );
  }
}

// POST - Add a new video source
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { animeId, episode, language, url, quality } = body;

    if (!animeId || !episode || !language || !url) {
      return NextResponse.json(
        { success: false, error: 'Missing required fields: animeId, episode, language, url' },
        { status: 400 }
      );
    }

    if (!['VF', 'VOSTFR'].includes(language)) {
      return NextResponse.json(
        { success: false, error: 'language must be VF or VOSTFR' },
        { status: 400 }
      );
    }

    const source = await addVideoSource({
      animeId,
      episode,
      language,
      source: 'Manual',
      url,
      quality,
    });

    return NextResponse.json({
      success: true,
      data: source,
    });
  } catch (error) {
    console.error('Error adding video source:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to add video source' },
      { status: 500 }
    );
  }
}

// DELETE - Remove a video source
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const id = searchParams.get('id');

    if (!id) {
      return NextResponse.json(
        { success: false, error: 'id is required' },
        { status: 400 }
      );
    }

    await deleteVideoSource(id);

    return NextResponse.json({
      success: true,
      message: 'Video source deleted',
    });
  } catch (error) {
    console.error('Error deleting video source:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to delete video source' },
      { status: 500 }
    );
  }
}

