src/app/api/backup/route.ts.content:
import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join } from 'path';

// File paths for backup
const PAGE_TSX_PATH = join(process.cwd(), 'src/app/page.tsx');
const ROUTE_TS_PATH = join(process.cwd(), 'src/app/api/frivox/route.ts');
const ANILIST_TS_PATH = join(process.cwd(), 'src/lib/anilist.ts');

// Get all backups
export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const action = searchParams.get('action');
  const versionName = searchParams.get('version');

  try {
    // Get specific backup
    if (action === 'get' && versionName) {
      const backup = await db.versionBackup.findUnique({
        where: { versionName },
      });

      if (!backup) {
        return NextResponse.json(
          { success: false, error: 'Version not found' },
          { status: 404 }
        );
      }

      return NextResponse.json({
        success: true,
        data: {
          id: backup.id,
          versionName: backup.versionName,
          description: backup.description,
          isLocked: backup.isLocked,
          createdAt: backup.createdAt,
          updatedAt: backup.updatedAt,
          // Don't return full code by default, too large
          hasPageTsx: !!backup.pageTsx,
          hasRouteTs: !!backup.routeTs,
          hasAnilistTs: !!backup.anilistTs,
        },
      });
    }

    // Get full backup for restore
    if (action === 'download' && versionName) {
      const backup = await db.versionBackup.findUnique({
        where: { versionName },
      });

      if (!backup) {
        return NextResponse.json(
          { success: false, error: 'Version not found' },
          { status: 404 }
        );
      }

      return NextResponse.json({
        success: true,
        data: backup,
      });
    }

    // List all backups
    const backups = await db.versionBackup.findMany({
      orderBy: { createdAt: 'desc' },
      select: {
        id: true,
        versionName: true,
        description: true,
        isLocked: true,
        createdAt: true,
        updatedAt: true,
      },
    });

    return NextResponse.json({
      success: true,
      data: backups,
      currentFiles: {
        pageTsx: existsSync(PAGE_TSX_PATH),
        routeTs: existsSync(ROUTE_TS_PATH),
        anilistTs: existsSync(ANILIST_TS_PATH),
      },
    });
  } catch (error) {
    console.error('Backup GET error:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to get backups' },
      { status: 500 }
    );
  }
}

// Create a new backup
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { versionName, description, lock } = body;

    if (!versionName) {
      return NextResponse.json(
        { success: false, error: 'Version name is required' },
        { status: 400 }
      );
    }

    // Check if version already exists
    const existing = await db.versionBackup.findUnique({
      where: { versionName },
    });

    if (existing) {
      return NextResponse.json(
        { success: false, error: 'Version name already exists' },
        { status: 400 }
      );
    }

    // Read current files
    let pageTsx = '';
    let routeTs = '';
    let anilistTs = '';

    try {
      pageTsx = readFileSync(PAGE_TSX_PATH, 'utf-8');
    } catch {
      console.warn('Could not read page.tsx');
    }

    try {
      routeTs = readFileSync(ROUTE_TS_PATH, 'utf-8');
    } catch {
      console.warn('Could not read route.ts');
    }

    try {
      anilistTs = readFileSync(ANILIST_TS_PATH, 'utf-8');
    } catch {
      console.warn('Could not read anilist.ts');
    }

    // Create backup
    const backup = await db.versionBackup.create({
      data: {
        versionName,
        description: description || `Backup created on ${new Date().toLocaleDateString('fr-FR')}`,
        pageTsx,
        routeTs,
        anilistTs,
        isLocked: lock || false,
      },
    });

    return NextResponse.json({
      success: true,
      data: {
        id: backup.id,
        versionName: backup.versionName,
        description: backup.description,
        isLocked: backup.isLocked,
        createdAt: backup.createdAt,
        fileSizes: {
          pageTsx: pageTsx.length,
          routeTs: routeTs.length,
          anilistTs: anilistTs.length,
        },
      },
    });
  } catch (error) {
    console.error('Backup POST error:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to create backup' },
      { status: 500 }
    );
  }
}

// Restore a backup
export async function PUT(request: NextRequest) {
  try {
    const body = await request.json();
    const { versionName, confirm } = body;

    if (!versionName) {
      return NextResponse.json(
        { success: false, error: 'Version name is required' },
        { status: 400 }
      );
    }

    if (!confirm) {
      return NextResponse.json(
        { success: false, error: 'Please confirm the restore with confirm: true' },
        { status: 400 }
      );
    }

    // Get backup
    const backup = await db.versionBackup.findUnique({
      where: { versionName },
    });

    if (!backup) {
      return NextResponse.json(
        { success: false, error: 'Version not found' },
        { status: 404 }
      );
    }

    // Restore files
    let restored = {
      pageTsx: false,
      routeTs: false,
      anilistTs: false,
    };

    if (backup.pageTsx) {
      try {
        writeFileSync(PAGE_TSX_PATH, backup.pageTsx, 'utf-8');
        restored.pageTsx = true;
      } catch (e) {
        console.error('Failed to restore page.tsx:', e);
      }
    }

    if (backup.routeTs) {
      try {
        writeFileSync(ROUTE_TS_PATH, backup.routeTs, 'utf-8');
        restored.routeTs = true;
      } catch (e) {
        console.error('Failed to restore route.ts:', e);
      }
    }

    if (backup.anilistTs) {
      try {
        writeFileSync(ANILIST_TS_PATH, backup.anilistTs, 'utf-8');
        restored.anilistTs = true;
      } catch (e) {
        console.error('Failed to restore anilist.ts:', e);
      }
    }

    return NextResponse.json({
      success: true,
      message: `Restored version: ${versionName}`,
      restored,
    });
  } catch (error) {
    console.error('Backup PUT error:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to restore backup' },
      { status: 500 }
    );
  }
}

// Delete a backup
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const versionName = searchParams.get('version');

    if (!versionName) {
      return NextResponse.json(
        { success: false, error: 'Version name is required' },
        { status: 400 }
      );
    }

    // Check if backup exists and is locked
    const backup = await db.versionBackup.findUnique({
      where: { versionName },
    });

    if (!backup) {
      return NextResponse.json(
        { success: false, error: 'Version not found' },
        { status: 404 }
      );
    }

    if (backup.isLocked) {
      return NextResponse.json(
        { success: false, error: 'Cannot delete locked backup' },
        { status: 403 }
      );
    }

    await db.versionBackup.delete({
      where: { versionName },
    });

    return NextResponse.json({
      success: true,
      message: `Deleted version: ${versionName}`,
    });
  } catch (error) {
    console.error('Backup DELETE error:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to delete backup' },
      { status: 500 }
    );
  }
}

