import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';

// GET - Fetch all watch history
export async function GET() {
  try {
    const history = await db.watchHistory.findMany({
      orderBy: {
        watchedAt: 'desc',
      },
      take: 20,
    });

    return NextResponse.json({
      success: true,
      data: history,
    });
  } catch (error) {
    console.error('Error fetching watch history:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch watch history' },
      { status: 500 }
    );
  }
}

// POST - Save or update watch history
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const {
      animeSlug,
      animeTitle,
      animeCover,
      seasonLabel,
      episodeNumber,
      language,
      videoUrl,
    } = body;

    if (!animeSlug || !animeTitle || !seasonLabel || episodeNumber === undefined || !language || !videoUrl) {
      return NextResponse.json(
        { success: false, error: 'Missing required fields' },
        { status: 400 }
      );
    }

    // Upsert - update if exists, create if not
    const history = await db.watchHistory.upsert({
      where: {
        animeSlug_seasonLabel_episodeNumber_language: {
          animeSlug,
          seasonLabel,
          episodeNumber,
          language,
        },
      },
      create: {
        animeSlug,
        animeTitle,
        animeCover,
        seasonLabel,
        episodeNumber,
        language,
        videoUrl,
      },
      update: {
        watchedAt: new Date(),
        animeTitle,
        animeCover,
        videoUrl,
      },
    });

    return NextResponse.json({
      success: true,
      data: history,
    });
  } catch (error) {
    console.error('Error saving watch history:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to save watch history' },
      { status: 500 }
    );
  }
}

// DELETE - Remove from watch history
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const id = searchParams.get('id');

    if (!id) {
      return NextResponse.json(
        { success: false, error: 'ID is required' },
        { status: 400 }
      );
    }

    await db.watchHistory.delete({
      where: { id },
    });

    return NextResponse.json({
      success: true,
      message: 'Watch history entry deleted',
    });
  } catch (error) {
    console.error('Error deleting watch history:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to delete watch history' },
      { status: 500 }
    );
  }
}

