import { NextRequest, NextResponse } from 'next/server'
import { db } from '@/lib/db'

// GET /api/episodes/[id] - Get episode details with video sources
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params

    const episode = await db.episode.findUnique({
      where: { id },
      include: {
        season: {
          include: {
            anime: {
              select: {
                id: true,
                title: true,
                slug: true,
                coverImage: true
              }
            }
          }
        },
        videoSources: {
          orderBy: [
            { language: 'asc' },
            { priority: 'desc' }
          ]
        }
      }
    })

    if (!episode) {
      return NextResponse.json(
        { success: false, error: 'Episode not found' },
        { status: 404 }
      )
    }

    // Increment view count
    await db.episode.update({
      where: { id: episode.id },
      data: { views: { increment: 1 } }
    })

    // Get next and previous episodes
    const [prevEpisode, nextEpisode] = await Promise.all([
      db.episode.findFirst({
        where: {
          seasonId: episode.seasonId,
          number: { lt: episode.number }
        },
        orderBy: { number: 'desc' },
        select: { id: true, number: true, title: true }
      }),
      db.episode.findFirst({
        where: {
          seasonId: episode.seasonId,
          number: { gt: episode.number }
        },
        orderBy: { number: 'asc' },
        select: { id: true, number: true, title: true }
      })
    ])

    // Group sources by language
    const sources = {
      vostfr: episode.videoSources
        .filter(s => s.language === 'vostfr')
        .sort((a, b) => b.priority - a.priority),
      vf: episode.videoSources
        .filter(s => s.language === 'vf')
        .sort((a, b) => b.priority - a.priority)
    }

    return NextResponse.json({
      success: true,
      data: {
        episode: {
          id: episode.id,
          number: episode.number,
          title: episode.title,
          description: episode.description,
          thumbnail: episode.thumbnail,
          duration: episode.duration,
          isFiller: episode.isFiller,
          views: episode.views,
          season: {
            id: episode.season.id,
            number: episode.season.number,
            title: episode.season.title
          },
          anime: episode.season.anime,
          sources,
          navigation: {
            prev: prevEpisode,
            next: nextEpisode
          }
        }
      }
    })

  } catch (error) {
    console.error('Error fetching episode:', error)
    return NextResponse.json(
      { success: false, error: 'Failed to fetch episode' },
      { status: 500 }
    )
  }
}

