import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';

/**
 * GET /api/updates - Get additional episodes for an anime
 * Query params:
 * - slug: anime slug (optional, if not provided returns all updates)
 */
export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const slug = searchParams.get('slug');

  try {
    if (slug) {
      // Get additional episodes for specific anime
      const episodes = await db.additionalEpisode.findMany({
        where: {
          animeSlug: slug,
          isActive: true,
        },
        orderBy: [
          { season: 'asc' },
          { episode: 'asc' },
        ],
      });

      const update = await db.animeUpdate.findUnique({
        where: { animeSlug: slug },
      });

      return NextResponse.json({
        success: true,
        data: {
          episodes,
          update,
        },
      });
    }

    // Get all animes with updates
    const updates = await db.animeUpdate.findMany({
      where: { hasUpdates: true },
      orderBy: { updatedAt: 'desc' },
      take: 100,
    });

    return NextResponse.json({
      success: true,
      data: updates,
    });
  } catch (error) {
    console.error('Updates error:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to get updates' },
      { status: 500 }
    );
  }
}
